mapper.select:
/* SQL ID : OrgMenuDAO.list 설 명 : 기관 메뉴의 전체 목록 */
SELECT A.ORG_ID , A.MENU_ID , A.MENU_TYCD , A.MENUNM , A.UP_MENU_ID , NVL(( SELECT MENUNM FROM TB_LMS_MENU WHERE MENU_ID = A.UP_MENU_ID GROUP BY MENUNM),'ROOT') AS PAR_MENU_NM , A.MENU_LV , CASE WHEN (A.MENU_LV -1) < 0 THEN 0 ELSE (A.MENU_LV -1) END AS PAR_MENU_LVL , A.MENU_SEQ , A.MENU_URL , A.MENU_PATH , A.MENU_EXPLN , A.USEYN , A.UPEND_MENUYN , A.TOP_MENU_IMG , A.LEFT_SIDE_MENU_IMG , A.LEFT_SIDE_MENU_TTL , A.MENU_TTL , A.BRDRLN_USEYN , A.OPTN_CTGR_CD_1 , A.OPTN_CD_1 , A.OPTN_CTGR_CD_2 , A.OPTN_CD_2 , A.OPTN_CTGR_CD_3 , A.OPTN_CD_3 , A.OPTN_CTGR_CD_4 , A.OPTN_CD_4 , A.OPTN_CTGR_CD_5 , A.OPTN_CD_5 , A.SSL_USEYN , A.RGTR_ID , '' AS RGTRNM , A.FRST_INQ_DTTM , A.MDFR_ID , '' AS MOD_NM , A.MOD_DTTM , NVL(B.VIEW_AUTH,'N') AS VIEW_AUTH , NVL(B.REG_AUTHRTYN,'N') AS REG_AUTHRTYN , NVL(B.MOD_AUTHRTYN,'N') AS MOD_AUTHRTYN , NVL(B.DEL_AUTH,'N') AS DEL_AUTH , ( SELECT COUNT(*) FROM TB_LMS_MENU WHERE MENU_TYCD = A.MENU_TYCD AND UP_MENU_ID = A.MENU_ID ) AS SUB_CNT FROM TB_LMS_MENU A LEFT OUTER JOIN TB_LMS_AUTHRT B ON A.MENU_TYCD = B.MENU_TYCD AND A.MENU_ID = B.MENU_ID AND #{authGrpCd} LIKE '%' || B.USER_AUTHRT_ID || '%' WHERE A.ORG_ID = #{orgId}
AND A.MENU_TYCD = #{menuType}
AND A.UP_MENU_ID = #{parMenuCd}
ORDER BY MENU_LV, MENU_SEQ

/* SQL ID : OrgMenuDAO.select 설 명 : 기관 메뉴의 정보 조회 */
SELECT A.ORG_ID , A.MENU_ID , A.MENU_TYCD , A.MENUNM , A.UP_MENU_ID , IFNULL(( SELECT MENUNM FROM TB_LMS_MENU WHERE MENU_ID = A.UP_MENU_ID),'ROOT') AS PAR_MENU_NM , A.MENU_LV as menuLvl , CASE WHEN (A.MENU_LV -1) < 0 THEN 0 ELSE (A.MENU_LV -1) END AS PAR_MENU_LVL , A.MENU_SEQ , A.MENU_URL , A.MENU_PATH , A.MENU_EXPLN , A.USEYN , A.UPEND_MENUYN , A.TOP_MENU_IMG , A.LEFT_SIDE_MENU_IMG , A.LEFT_SIDE_MENU_TTL , A.MENU_TTL , A.BRDRLN_USEYN , A.OPTN_CTGR_CD_1 , A.OPTN_CD_1 , A.OPTN_CTGR_CD_2 , A.OPTN_CD_2 , A.OPTN_CTGR_CD_3 , A.OPTN_CD_3 , A.OPTN_CTGR_CD_4 , A.OPTN_CD_4 , A.OPTN_CTGR_CD_5 , A.OPTN_CD_5 , A.SSL_USEYN , A.RGTR_ID , '' AS RGTRNM , A.FRST_INQ_DTTM , A.MDFR_ID , '' AS MOD_NM , A.MOD_DTTM as modDttm , ( SELECT COUNT(*) FROM TB_LMS_MENU WHERE MENU_TYCD = A.MENU_TYCD AND UP_MENU_ID = A.MENU_ID ) AS SUB_CNT FROM TB_LMS_MENU A WHERE A.ORG_ID = #{orgId}
AND A.MENU_TYCD = #{menuType}
AND A.MENU_ID = #{menuCd}

/* SQL ID : OrgMenuDAO.listAuthGrpMenu 설 명 : 입력된 권한 그룹의 전체 메뉴 목록 */
SELECT DISTINCT A.ORG_ID , A.MENU_ID , A.MENU_TYCD , A.MENUNM , A.UP_MENU_ID , IFNULL(( SELECT MENUNM FROM TB_LMS_MENU WHERE MENU_ID = A.UP_MENU_ID),'ROOT') AS PAR_MENU_NM , A.MENU_LV , CASE WHEN (A.MENU_LV -1) < 0 THEN 0 ELSE (A.MENU_LV -1) END AS PAR_MENU_LVL , A.MENU_SEQ , A.MENU_URL , A.MENU_PATH , A.MENU_EXPLN , A.USEYN , A.UPEND_MENUYN , A.TOP_MENU_IMG , A.LEFT_SIDE_MENU_IMG , A.LEFT_SIDE_MENU_TTL , A.MENU_TTL , A.BRDRLN_USEYN , A.OPTN_CTGR_CD_1 , A.OPTN_CD_1 , A.OPTN_CTGR_CD_2 , A.OPTN_CD_2 , A.OPTN_CTGR_CD_3 , A.OPTN_CD_3 , A.OPTN_CTGR_CD_4 , A.OPTN_CD_4 , A.OPTN_CTGR_CD_5 , A.OPTN_CD_5 , A.SSL_USEYN , A.RGTR_ID , '' AS RGTRNM , A.FRST_INQ_DTTM , A.MDFR_ID , '' AS MOD_NM , A.MOD_DTTM , IFNULL(B.VIEW_AUTH,'N') AS VIEW_AUTH , IFNULL(B.REG_AUTHRTYN,'N') AS REG_AUTHRTYN , IFNULL(B.MOD_AUTHRTYN,'N') AS MOD_AUTHRTYN , IFNULL(B.DEL_AUTH,'N') AS DEL_AUTH , ( SELECT COUNT(*) FROM TB_LMS_MENU WHERE MENU_TYCD = A.MENU_TYCD AND UP_MENU_ID = A.MENU_ID ) AS SUB_CNT FROM TB_LMS_MENU A LEFT OUTER JOIN TB_LMS_AUTHRT B ON A.MENU_TYCD = B.MENU_TYCD AND A.MENU_ID = B.MENU_ID AND #{authGrpCd} LIKE CONCAT('%',B.USER_AUTHRT_ID,'%') COLLATE utf8mb4_general_ci WHERE A.ORG_ID = #{orgId}
AND A.USEYN = 'Y' AND A.MENU_TYCD = #{menuType}
AND A.UP_MENU_ID = #{parMenuCd}
ORDER BY MENU_LV, MENU_SEQ

mapper.insert:
	/*
		 SQL ID : OrgMenuDAO.insert
		 설  명 : 기관 메뉴의 정보 등록
 	*/
	INSERT INTO TB_LMS_MENU (
	       ORG_ID
	     , MENU_ID
	     , UP_MENU_ID
	     , MENU_TYCD
	     , MENUNM
	     , MENU_LV
	     , MENU_SEQ
	     , MENU_URL
	     , MENU_PATH
	     , MENU_EXPLN
	     , USEYN
		 , LEFT_SIDE_MENU_IMG
	     , MENU_TTL
	     , OPTN_CTGR_CD_1
	     , OPTN_CD_1
	     , OPTN_CTGR_CD_2
	     , OPTN_CD_2
	     , OPTN_CTGR_CD_3
	     , OPTN_CD_3
	     , OPTN_CTGR_CD_4
	     , OPTN_CD_4
	     , OPTN_CTGR_CD_5
	     , OPTN_CD_5
	     , SSL_USEYN
	     , BRDRLN_USEYN
	     , BSCYN
	     , MENU_INQYN
	     , RGTR_ID
	     , FRST_INQ_DTTM
	     , MDFR_ID
	     , MOD_DTTM
	) VALUES (     
	       #{orgId}
	     , #{menuCd}
	     , #{parMenuCd}
	     , #{menuType}
	     , #{menuNm}
	     , #{menuLvl}
	     , ( SELECT MAX(IFNULL(A.MENU_SEQ,0)) + 1
	           FROM TB_LMS_MENU A
	          WHERE A.ORG_ID = #{orgId}
	            AND A.MENU_TYCD = #{menuType}
	            AND IFNULL(A.UP_MENU_ID,'1') = IFNULL(#{parMenuCd},'1') )
	     , #{menuUrl}
	     , #{menuPath}
	     , #{menuDesc}
	     , #{useYn}
	     , #{leftMenuImg}
	     , #{menuTitle}
	     , #{optnCtgrCd1}
	     , #{optnCd1}
	     , #{optnCtgrCd2}
	     , #{optnCd2}
	     , #{optnCtgrCd3}
	     , #{optnCd3}
	     , #{optnCtgrCd4}
	     , #{optnCd4}
	     , #{optnCtgrCd5}
	     , #{optnCd5}
	     , #{sslYn}
	     , #{divLineUseYn}
	     , 'N' 
	     , #{menuViewYn}
	     , #{rgtrId}
	     , FN_DTTM()
	     , #{mdfrId}
	     , FN_DTTM()
	)

mapper.update:
	/*
		 SQL ID : OrgMenuDAO.update
		 설  명 : 기관 메뉴의 정보 수정
 	*/
	UPDATE TB_LMS_MENU
	   SET MENUNM = #{menuNm}

	     , UP_MENU_ID = #{parMenuCd}


	     , MENU_LV = #{menuLvl}


	     , MENU_SEQ = #{menuOdr}


	     , MENU_URL = #{menuUrl}


	     , MENU_PATH = #{menuPath}


	     , MENU_EXPLN = #{menuDesc}


	     , USEYN = #{useYn}


	     , LEFT_SIDE_MENU_IMG = #{leftMenuImg}


	     , MENU_TTL = #{menuTitle}


	     , OPTN_CTGR_CD_1 = #{optnCtgrCd1}


	     , OPTN_CD_1 = #{optnCd1}


	     , OPTN_CTGR_CD_2 = #{optnCtgrCd2}


	     , OPTN_CD_2 = #{optnCd2}


	     , OPTN_CTGR_CD_3 = #{optnCtgrCd3}


	     , OPTN_CD_3 = #{optnCd3}


	     , OPTN_CTGR_CD_4 = #{optnCtgrCd4}


	     , OPTN_CD_4 = #{optnCd4}


	     , OPTN_CTGR_CD_5 = #{optnCtgrCd5}


	     , OPTN_CD_5 = #{optnCd5}


	     , SSL_USEYN = #{sslYn}


	     , BRDRLN_USEYN = #{divLineUseYn}


	     , MENU_INQYN = #{menuViewYn}

	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = FN_DTTM()
	 WHERE ORG_ID = #{orgId}
	   AND MENU_TYCD = #{menuType}
	   AND MENU_ID = #{menuCd}

mapper.delete:
	/*
		 SQL ID : OrgMenuDAO.delete
		 설  명 : 기관 메뉴의 정보 삭제
 	*/
	DELETE FROM TB_LMS_MENU
	 WHERE ORG_ID = #{orgId}
	   AND MENU_TYCD = #{menuType}
	   AND MENU_ID = #{menuCd}

	/*
		 SQL ID : OrgMenuDAO.deleteByMenuLvl
		 설  명 : 기관 메뉴의 초기화 삭제 (레벨별로 삭제)
 	*/
 	DELETE FROM TB_LMS_MENU
	 WHERE ORG_ID = #{orgId}
	   AND MENU_TYCD = #{menuType}
	   AND MENU_LV = #{menuLvl}

mapper.select:
/* SQL ID : OrgMenuDAO.selectMenuSimpleInfo 설 명 : 메뉴 의 간략 정보 조회 */
SELECT A.MENU_ID , A.MENU_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'MENU_TYCD' AND CD = A.MENU_TYCD) AS MENU_TYPE_NM , NVL(A.MENUNM, '') AS MENUNM FROM TB_LMS_MENU A
WHERE A.MENU_ID = #{menuCd} AND A.ORG_ID = #{orgId}
